<?php
namespace App\Http\Controllers\mobile;

use App\Models\SarHeader;
use App\Models\SarDetail;
use App\Models\ProsesFdlSar;
use App\Models\ParameterSar;

use Carbon\Carbon;
use Laravel\Lumen\Routing\Controller;
use Illuminate\Http\Request;

use App\Services\GenerateStrukSarService;
Carbon::setLocale('id'); // Set locale ke Indonesia untuk format tanggal

class PrintTermalController extends Controller
{
    public function createPrintJob(Request $request)
    {
        try {
            $formatTanggal = function ($dateStr) {
                if (!$dateStr) return '-';
    
                try {
                    Carbon::setLocale('id');
    
                    return Carbon::parse($dateStr)
                        ->translatedFormat('l, d F Y H:i');
                } catch (\Exception $e) {
                    return $dateStr;
                }
            };
    
            $noOrder   = $request->input('no_order');
            $printMode = 'full'; // 'full' atau 'filled'
    
            $header = SarHeader::with('detail')
                        ->where('is_active', true)
                        ->where('no_order', $noOrder)
                        ->first();
    
            if (!$header) {
                return response()->json(['error' => 'Data tidak ditemukan'], 404);
            }
    
            $nilai_rujukan = ParameterSar::select('id_parameter', 'nama_lab', 'nama_regulasi', 'nilai_rujukan')
                                ->where('is_active', true)
                                ->get();
    
            $groupedBySample = $header->detail->groupBy('nomor_sampel');
    
            $sampel_groups = $groupedBySample->map(function ($details, $nomor_sampel) use ($nilai_rujukan, $printMode) {
                $detailMap = $details->keyBy('id_parameter');
                $lokasi    = $details->first()->lokasi_pengambilan_sampel ?? '-';
    
                $parameters = $nilai_rujukan->map(function ($param) use ($detailMap) {
                    $detail    = $detailMap->get($param->id_parameter);
                    $hasil_uji = $detail ? $detail->hasil_uji : '-';
                    $melebihi  = false;
    
                    if ($detail && is_numeric($hasil_uji) && is_numeric($param->nilai_rujukan)) {
                        $melebihi = (float)$hasil_uji > (float)$param->nilai_rujukan;
                    }
    
                    return [
                        'nama_regulasi'    => $param->nama_regulasi,
                        'hasil_uji'        => $hasil_uji,
                        'nilai_rujukan'    => $param->nilai_rujukan,
                        'melebihi_rujukan' => $melebihi,
                        '_has_value'       => $detail !== null
                                                && $hasil_uji !== null
                                                && $hasil_uji !== ''
                                                && $hasil_uji !== '-',
                    ];
                });
    
                // Filter sesuai mode
                if ($printMode === 'filled') {
                    $parameters = $parameters->filter(fn($p) => $p['_has_value'])->values();
                }
    
                // Buang key internal
                $parameters = $parameters->map(function ($p) {
                    unset($p['_has_value']);
                    return $p;
                })->values();
    
                return [
                    'nomor_sampel'    => $nomor_sampel,
                    'lokasi'          => $lokasi,
                    'item_parameters' => $parameters,
                ];
            })->values();
            
            // INIT ARRAY DULU
            $payload = [];
    
            $logoPath = public_path('isl_logo.png');
            $logoBase64 = 'data:image/png;base64,';
            // $logoBase64='';
            $htmlReceipt = "
            
            <div style='
                font-family: Roboto, Arial, sans-serif;
                font-size: 18px;
                width: 100%;
                color: #000;
                line-height: 1.2;
            '>
    
                <!-- HEADER -->
                <div style='font-family: Roboto, Arial, sans-serif; font-size: 18px; width: 100%; color: #000; line-height: 1.2; margin: 0; padding: 0;'>
                    <div style='width: 100%; font-family: sans-serif; margin: 0; padding: 0; color: #000;'>
                        <div style='text-align: center; margin-bottom: 5px; padding-bottom: 2px;'>
                            <img src='{$logoBase64}' style='width: 130px; height: auto; margin-bottom: 6px;' alt='Logo'>
                            <div style='font-size: 17px; line-height: 1.3; text-align: left; box-sizing: border-box; padding-right: 20px; padding-left:0;'>
                                Ruko Icon Business Park Blok O No.5-6 BSD City<br>Jl. BSD Raya Utama, Cisauk, Sampora, Kab. Tangerang 15341
                            </div>
                        </div>
                    </div>
                </div>
    
                <div style='border-bottom:2px dashed #000; margin:4px 0;'></div>
    
                <!-- ORDER -->
                <table style='
                    width:100%;
                    font-size: 18px;
                    border-collapse:collapse;
                    line-height:1.2;
                '>
                    <tr>
                        <td style='width:35%'>No. Order</td>
                        <td style='width:5%'>:</td>
                        <td style='word-break:break-word'>
                            {$header->no_order}
                        </td>
                    </tr>
    
                    <tr>
                        <td>No. Quotation</td>
                        <td>:</td>
                        <td style='word-break:break-word'>
                            {$header->no_quotation}
                        </td>
                    </tr>
    
                    <tr>
                        <td>Pelanggan</td>
                        <td>:</td>
                        <td>
                            {$header->nama_pelanggan}
                        </td>
                    </tr>
    
                    <tr>
                        <td>E-Mail</td>
                        <td>:</td>
                        <td style='word-break:break-word'>
                            {$header->email_pelanggan}
                        </td>
                    </tr>
                </table>
    
                {$this->buildSampelHtmlFromGroups($sampel_groups)}
    
                <div style='border-bottom:2px dashed #000; margin:4px 0;'></div>
    
                <!-- KETERANGAN -->
                <div style='font-size: 18px; line-height:1.2;'>
                    <div style='font-weight:bold; margin-bottom:2px;'>
                        KETERANGAN
                    </div>
                    <div>
                        * = HASIL UJI melebihi nilai rujukan
                    </div>
                </div>
    
                <div style='border-bottom:2px dashed #000; margin:4px 0;'></div>
    
                <!-- FOOTER INFO -->
                <table style='
                    width:100%;
                    font-size: 18px;
                    border-collapse:collapse;
                    line-height:1.2;
                '>
                    <tr>
                        <td style='width:35%'>Tanggal</td>
                        <td style='width:5%'>:</td>
                        <td>
                            " . $formatTanggal($header->waktu_mulai_sampling) . "
                        </td>
                    </tr>
    
                    <tr>
                        <td>Petugas</td>
                        <td>:</td>
                        <td>
                            " . (
                                $header->detail->first()->created_by
                                ?? $header->detail->first()->updated_by
                                ?? '-'
                            ) . "
                        </td>
                    </tr>
                </table>
    
                <div style='border-bottom:2px dashed #000; margin:4px 0;'></div>
    
                <!-- THANK YOU -->
                <div style='
                    width: 100%; 
                    margin: 0 auto; 
                    box-sizing: border-box; 
                    text-align: center; 
                    font-size: 18px; 
                    line-height: 1.3; 
                    padding-top: 2px;
                    padding-right: 40px;
                '>
                    Terima kasih telah melakukan pengujian di<br>
                    <strong>PT. Inti Surya Laboratorium</strong><br>
                    T: 021-5088-9889<br>
                    sales@intilab.com
                </div>
    
                <!-- EXTRA SPACE BUAT SOBEK -->
                <div style='height:30px;'></div>
    
            </div>
            ";
    
            $struk = new \stdClass();
            $struk->type = 4;
            $struk->content = $htmlReceipt;
            array_push($payload, $struk);
    
            return response(json_encode($payload, JSON_FORCE_OBJECT), 200)
                    ->header('Content-Type', 'application/json')
                    ->header('Cache-Control', 'no-store, no-cache, must-revalidate, max-age=0')
                    ->header('Pragma', 'no-cache')
                    ->header('Expires', '0');
            
        } catch (\Throwable $th) {
            //throw $th;
            $dataLog=[
                "message"=>$th->getMessage(),
                "line"=>$th->getLine(),
                "file" => $th->getFile()
            ];
            \Log::error('error pinter termal',$dataLog);
        }
    }

    private function buildSampelHtmlFromGroups($sampel_groups): string
    {
        $html = '';

        foreach ($sampel_groups as $group) {
            $nomor_sampel = $group['nomor_sampel'] ?? '-';
            $lokasi       = !empty(trim($group['lokasi'] ?? '')) && $group['lokasi'] !== '-'
                                ? $group['lokasi']
                                : 'Lokasi tidak diisi';
            $parameters   = $group['item_parameters'] ?? [];

            $html .= "
            <div style='border-bottom: 2px dashed #000; margin: 4px 0;'></div>

            <table style='width: 100%; font-size: 15px; border-collapse: collapse; line-height: 1.3;'>
                <tr>
                    <td style='font-weight:bold; width:38%'>{$nomor_sampel}</td>
                    <td style='width:2%'>:</td>
                    <td style='font-weight:bold; word-break:break-word'>{$lokasi}</td>
                </tr>
            </table>

            <div style='border-bottom: 2px dashed #000; margin: 3px 0;'></div>

            <table style='width: 100%; font-size: 15px; border-collapse: collapse; line-height: 1.3;'>
                <thead>
                    <tr>
                        <td style='font-weight:bold; width:44%'>Parameter</td>
                        <td style='font-weight:bold; text-align:center; width:20%'>Hasil</td>
                        <td style='font-weight:bold; text-align:center; width:36%'>Rujukan</td>
                    </tr>
                </thead>
                <tbody>";

            foreach ($parameters as $p) {
                $hasilRaw = $p['hasil_uji'] ?? null;
                $hasil    = ($hasilRaw === null || $hasilRaw === '' || $hasilRaw === 'null' || $hasilRaw === '-')
                                ? '-'
                                : $hasilRaw;
                $tanda    = !empty($p['melebihi_rujukan']) ? ' *' : ''; // ganti ↗ ke * lebih aman di thermal

                $html .= "
                    <tr>
                        <td style='padding: 0; word-break:break-word'>" . ($p['nama_regulasi'] ?? '-') . "</td>
                        <td style='text-align:center; padding:0'>" . $hasil . $tanda . "</td>
                        <td style='text-align:center; padding:0; color:#333'>" . ($p['nilai_rujukan'] ?? '-') . "</td>
                    </tr>";
            }

            $html .= "
                </tbody>
            </table>";
        }

        return $html ?: "<div style='font-size: 15px; text-align:center;'>Data parameter tidak ditemukan.</div>";
    }

}